namespace optiling {

// UB budget: 4 buffers (2 for in, 2 for out) each of tileLen floats => 16*bytes per element
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative per-core share
static constexpr uint32_t ALIGN_ELEMS = 2048;            // favor larger DMA bursts

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    CumsumExclusiveCustomTilingData tiling;
    const auto& shape = context->GetInputShape(0)->GetOriginShape();
    const uint32_t totalLength = static_cast<uint32_t>(shape.GetShapeSize());

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *dimPtr = attrs->GetAttrPointer<int64_t>(0);
    int64_t dimVal = (dimPtr != nullptr) ? *dimPtr : 0;
    int64_t ndim = shape.GetDimNum();
    if (dimVal < 0) dimVal += ndim;
    uint32_t rowLength = (dimVal >= 0 && dimVal < ndim) ?
                         static_cast<uint32_t>(shape.GetDim(dimVal)) : 0u;

    // Safe tile length from UB budget: 4 buffers * 4 bytes = 16 bytes per element
    uint32_t maxTile = UB_BUDGET_BYTES / 16;  // elements
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;

    uint32_t tileLength = (rowLength > maxTile) ? maxTile : rowLength;
    if (tileLength == 0) tileLength = 1;

    const uint32_t numRows = (rowLength == 0) ? 0u : totalLength / rowLength;
    uint32_t blockDim = numRows;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLength);
    tiling.set_rowLength(rowLength);
    tiling.set_blockDim(blockDim);
    tiling.set_dim(dimVal);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

